const rows = $input.all();
const normalized = rows.map((item, index) => {
  const json = item.json || {};
  const topic = String(json.Topic || json.topic || '').trim();
  const description = String(json.Description || json.description || '').trim();
  const imageUrl = String(json.Image || json.image || json['Image URL'] || json.image_url || '').trim();
  const status = String(json.Status || json.status || '').trim().toLowerCase();
  const rowNumber = json.row_number || json.__rowNumber || json.rowIndex || json.row_index;
  return { item, index, json, topic, description, imageUrl, status, rowNumber };
});

const picked = normalized.find(row => {
  if (!row.topic || !row.imageUrl) return false;
  if (['posted', 'skipped', 'error', 'failed'].includes(row.status)) return false;
  return true;
});

if (!picked) {
  const withMissingImage = normalized.filter(row => row.topic && !row.imageUrl && !['posted', 'skipped', 'error', 'failed'].includes(row.status)).length;
  throw new Error(`No usable pending rows found. Add Topic + a public direct Image URL to at least one row. Pending rows missing Image: ${withMissingImage}.`);
}

if (!/^https?:\/\//i.test(picked.imageUrl)) {
  throw new Error(`Image URL for "${picked.topic}" must start with http:// or https://. Got: ${picked.imageUrl}`);
}

return [{
  json: {
    ...picked.json,
    Topic: picked.topic,
    Description: picked.description,
    Image: picked.imageUrl,
    row_number: picked.rowNumber,
    source_row_index: picked.index + 1
  },
  binary: picked.item.binary
}];

const row = $input.first().json;
  const topic = String(row.Topic || row.topic || '').trim();
  const description = String(row.Description || row.description || '').trim();
  const imageUrl = String(row.Image || row.image || row['Image URL'] || row.image_url || '').trim();
  const rowNumber = row.row_number || row.__rowNumber || row.rowIndex || row.row_index;

  if (!topic) throw new Error('Google Sheet row is missing Topic.');
  if (!imageUrl) throw new Error(`Google Sheet row for "${topic}" is missing Image URL. Add a public direct image URL in the Image column.`);
  if (!/^https?:\/\//i.test(imageUrl)) throw new Error(`Image URL for "${topic}" must start with http:// or https://. Got: ${imageUrl}`);

  const prompt = [
    'You are a system design educator posting on LinkedIn.',
    `Topic: ${topic}`,
    `Description: ${description}`,
    '',
    'Write one complete LinkedIn post between 900 and 2200 characters.',
    '- Start with a strong hook on the first line. Do not use Markdown symbols like ** or __.',
    '- Use clear comparisons with emojis as visual anchors.',
    '- Explain trade-offs simply for backend/system-design learners.',
    '- Keep the wording practical, clear, and comment-worthy.',
    '- Do not stop mid-section; every comparison you introduce must include its full explanation.',
    '- End with one question that drives comments.',
    '- Do not generate an image prompt or image description.',
    '',
    'Return ONLY valid JSON. No markdown fences. No commentary outside JSON.',
    'JSON schema:',
    '{ "post_text": "Complete LinkedIn caption" }'
  ].join('\n');

  return [{
    json: {
      ...row,
      row_number: rowNumber,
      topic,
      description,
      image_url: imageUrl,
      prompt,
      requestBody: {
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        generationConfig: { temperature: 0.75, responseMimeType: 'application/json' }
      }
    }
  }];

const gemini = $input.first().json;
const source = $('Build Gemini post request').first().json;

function extractTextFromGemini(value) {
  if (value?.candidates?.[0]?.content?.parts) {
    return value.candidates[0].content.parts.map(part => part.text || '').join('');
  }
  if (typeof value?.text === 'string') return value.text;
  if (typeof value?.post_text === 'string') return JSON.stringify(value);
  return JSON.stringify(value);
}

function stripJsonFence(value) {
  return String(value || '')
    .trim()
    .replace(/^\uFEFF/, '')
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
}

function parseJsonObject(raw) {
  const text = stripJsonFence(raw);
  try { return JSON.parse(text); } catch (_) {}

  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace > firstBrace) {
    const candidate = text.slice(firstBrace, lastBrace + 1);
    try { return JSON.parse(candidate); } catch (_) {}
  }

  if (text.length >= 80) return { post_text: text };
  throw new Error('Gemini did not return usable post text. Raw output: ' + text.slice(0, 1000));
}

function cleanPostText(value) {
  return String(value || '')
    .replace(/\r\n/g, '\n')
    .replace(/[\u200B-\u200D\uFEFF]/g, '')
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
    .replace(/^```[a-z]*\n?/i, '')
    .replace(/```$/i, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const parsed = parseJsonObject(extractTextFromGemini(gemini));
let postText = cleanPostText(parsed.post_text || parsed.postText || parsed.caption || parsed.text || '');

if (postText.length < 120) {
  postText = `${source.topic}: the system-design trade-off most teams miss\n\nGreat architecture is rarely about one perfect tool. It is about choosing the right balance between latency, consistency, cost, and operational complexity.\n\nWhich trade-off would you choose first?`;
}

if (!/\?\s*(?:#[A-Za-z0-9_]+\s*)*$/.test(postText)) {
  postText = postText.replace(/\s+$/, '') + '\n\nWhat trade-off would you choose first?';
}

const emergencyLinkedInCap = 2800;
if (postText.length > emergencyLinkedInCap) {
  const questions = postText.match(/[^\n.!?]*\?/g) || [];
  const question = cleanPostText(questions[questions.length - 1] || 'What trade-off would you choose first?');
  const room = emergencyLinkedInCap - question.length - 2;
  postText = postText.slice(0, room).replace(/\n[^\n]*$/, '').trim();
  postText += '\n\n' + question;
}

return [{
  json: {
    topic: source.topic,
    description: source.description,
    image_url: source.image_url,
    row_number: source.row_number,
    post_text: postText,
    post_text_length: postText.length,
    image_alt_text: `${source.topic} - system design infographic`.slice(0, 120)
  }
}];

const item = $input.first();
const image = item.binary?.image;
if (!image) throw new Error('Image download did not produce binary field named "image". Check that the Image column contains a direct public image URL.');

const mimeType = String(image.mimeType || 'application/octet-stream').toLowerCase();
if (!mimeType.startsWith('image/')) {
  throw new Error(`Downloaded URL did not return an image MIME type. Got ${mimeType} from ${item.json.image_url}`);
}
if (!/image\/(jpeg|jpg|png)/i.test(mimeType)) {
  throw new Error(`LinkedIn image upload in this workflow accepts JPG or PNG only. Got ${mimeType} from ${item.json.image_url}. Replace the sheet Image URL with a direct JPG/PNG URL.`);
}

const rawSize = image.fileSize || image.fileSizeBytes || image.dataSize || image.fileSizeBytesString;
const sizeBytes = Number(String(rawSize || '').replace(/[^0-9]/g, '')) || undefined;
const maxBytes = 10 * 1024 * 1024;
if (sizeBytes && sizeBytes > maxBytes) {
  throw new Error(`Downloaded image is too large for reliable LinkedIn upload (${sizeBytes} bytes). Use a JPG/PNG under 10MB.`);
}

const safeTopic = String(item.json.topic || 'linkedin-image').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 60) || 'linkedin-image';
const ext = mimeType.includes('png') ? 'png' : 'jpg';
image.fileName = image.fileName || `${safeTopic}.${ext}`;
image.mimeType = mimeType.includes('png') ? 'image/png' : 'image/jpeg';

return [{
  json: {
    ...item.json,
    image_mime_type: image.mimeType,
    image_file_name: image.fileName,
    image_size_bytes: sizeBytes,
  },
  binary: { image }
}];

const reg = $input.first().json;
const original = $('Prepare downloaded image').first();
const uploadUrl = reg.value?.uploadUrl || reg.uploadUrl;
const asset = reg.value?.image || reg.image;
if (!uploadUrl || !/^https?:\/\//i.test(uploadUrl)) {
  throw new Error('LinkedIn initializeUpload did not return a valid uploadUrl: ' + JSON.stringify(reg));
}
if (!asset || !String(asset).startsWith('urn:li:image:')) {
  throw new Error('LinkedIn initializeUpload did not return a valid image URN: ' + JSON.stringify(reg));
}
if (!original.binary?.image) {
  throw new Error('Downloaded image binary was lost before LinkedIn upload. Expected binary field "image".');
}

const escapeLinkedInLittleText = (value) => String(value || '')
  .replace(/\\/g, '\\\\')
  .replace(/[|{}@\[\]()<>#*_~]/g, '\\$&');

const rawCommentary = String(original.json.post_text || '').trim();
const linkedinCommentary = escapeLinkedInLittleText(rawCommentary);
if (!rawCommentary) throw new Error('Post text is empty before LinkedIn publish.');
if (linkedinCommentary.length > 3000) throw new Error(`Escaped LinkedIn commentary is unexpectedly long (${linkedinCommentary.length} chars). Shorten the generated text.`);

return [{
  json: {
    ...original.json,
    linkedin_commentary: linkedinCommentary,
    linkedin_commentary_length: linkedinCommentary.length,
    uploadUrl,
    asset
  },
  binary: { image: original.binary.image }
}];

const item = $input.first();
const query = item.json.query || {};
const action = String(query.action || item.json.action || '').trim().toLowerCase();
if (!['approve', 'skip'].includes(action)) {
  throw new Error(`Invalid approval action "${action || '(empty)'}". Use the Approve & Post or Skip link from the approval email.`);
}
return [{ json: { ...item.json, action }, binary: item.binary }];

const profile = $input.first().json;
const sub = String(profile.sub || '').trim();
if (!sub) {
  throw new Error('LinkedIn /v2/userinfo did not return a profile sub. Reconnect the Linkedin OAuth credential with openid profile w_member_social scopes.');
}
const author = `urn:li:person:${sub}`;
return [{ json: { ...profile, linkedin_author: author } }];
